<article class="docs-article inventory-page"><header class="article-header"><div class="article-kicker"><span>Private operations</span><span class="privacy-badge">Authenticated</span></div><h1>Infrastructure inventory</h1><p class="lead">A live index generated from service metadata in your Markdown frontmatter.</p><div class="article-meta"><span><?= count($services) ?> documented service<?= count($services) === 1 ? '' : 's' ?></span></div></header>
<?php if ($services): ?><div class="inventory-table"><div class="inventory-row inventory-head"><span>ID</span><span>Application</span><span>Address</span><span>Installation</span><span>Review</span></div><?php foreach ($services as $item): $page = $item['page']; $service = $item['service']; ?><a class="inventory-row" href="<?= $e($page->url) ?>"><span><?= isset($service['id']) ? 'CT ' . $e($service['id']) : '—' ?></span><span><strong><?= $e($service['application'] ?? $page->title) ?></strong><small><?= $e($service['type'] ?? 'service') ?></small></span><span><code><?= $e($service['address'] ?? '—') ?></code></span><span><?= $e($service['installation'] ?? 'documented') ?></span><span class="<?= $page->isReviewStale() ? 'stale' : '' ?>"><?= $page->reviewedAt() ? $e(date('M j, Y', $page->reviewedAt())) : 'Not reviewed' ?></span></a><?php endforeach; ?></div><?php else: ?><div class="empty-state"><h2>No services documented yet</h2><p>Add a `service` mapping to page frontmatter.</p></div><?php endif; ?>
</article>
